create table if not exists profiles (id uuid primary key, full_name text, phone text, role text default 'visitor', created_at timestamptz default now());
create table if not exists exhibitions (id uuid primary key default gen_random_uuid(), owner_id uuid, name text not null, city text, venue text, start_date date, end_date date, status text default 'draft', created_at timestamptz default now());
create table if not exists merchants (id uuid primary key default gen_random_uuid(), business_name text not null, license_number text, license_expires_at date, license_file_path text, created_at timestamptz default now());
create table if not exists booths (id uuid primary key default gen_random_uuid(), exhibition_id uuid references exhibitions(id) on delete cascade, booth_number text not null, price numeric default 0, reserved boolean default false, merchant_id uuid references merchants(id), created_at timestamptz default now());
create table if not exists bookings (id uuid primary key default gen_random_uuid(), exhibition_id uuid references exhibitions(id) on delete cascade, booth_id uuid references booths(id) on delete cascade, merchant_id uuid references merchants(id), status text default 'pending', amount numeric default 0, created_at timestamptz default now());
create table if not exists checkins (id uuid primary key default gen_random_uuid(), exhibition_id uuid references exhibitions(id) on delete cascade, visitor_name text, visitor_phone text, checked_in_at timestamptz default now());
